  position: relative;
  width: 100vw;
  height: 100vh;
  display: flex;
  justify-content: flex-end;
  align-items: flex-end;
  overflow: hidden;
}

.hero-img {
  position: absolute;
  top: 0%;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 0;
  transform: rotate(-165deg);
}

.hero-img img {
  transform: scale(1.25);
}

.hero-header {
  position: relative;
  width: 100%;
  display: flex;
  align-items: flex-start;
  padding: 1em;
  z-index: 1;
}

.hero-col:nth-child(1) {
  flex: 6;
}

.hero-col:nth-child(2) {
  flex: 2;
  padding: 0.5em;
}

.hero-header h1 {
  text-transform: uppercase;
  font-family: var(--font-secondary);
  font-size: 13vw;
