}

p#site-intro {
  text-indent: 10em;
  margin-top: 2em;
  text-transform: uppercase;
}

@media (max-width: 900px) {
  .hero-header {
    position: absolute;
    bottom: 10em;
    flex-direction: column;
  }

  p#site-intro {
    margin-top: 0;
    text-indent: 0;
  }

  .hero-img {
    transform: rotate(-170deg);
  }
}

